import{_ as t,o as a,c as o,a2 as s}from"./chunks/framework.C_beXv0I.js";const u=JSON.parse('{"title":"Concepts","description":"","frontmatter":{},"headers":[],"relativePath":"reference/concepts.md","filePath":"reference/concepts.md","lastUpdated":1783011651000}'),i={name:"reference/concepts.md"};function r(d,e,n,l,c,h){return a(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="concepts" tabindex="-1">Concepts <a class="header-anchor" href="#concepts" aria-label="Permalink to &quot;Concepts&quot;">​</a></h1><p>Muster is a glass-box, multi-runtime, multi-domain agentic orchestrator. This page covers the ideas that make it work. For the full source-level map, see <a href="/muster/reference/architecture">Architecture</a>.</p><h2 id="glass-box" tabindex="-1">Glass-box <a class="header-anchor" href="#glass-box" aria-label="Permalink to &quot;Glass-box&quot;">​</a></h2><p>Glass-box is the design constraint that shapes everything else. Every routing decision is inspectable: which role resolved to which provider, on which model, and why. Before any work starts, Muster shows a crew manifest and a plan. Nothing is hidden behind a single opaque prompt.</p><h2 id="two-layers" tabindex="-1">Two layers <a class="header-anchor" href="#two-layers" aria-label="Permalink to &quot;Two layers&quot;">​</a></h2><p>Muster is split into two layers with a hard boundary between them.</p><table tabindex="0"><thead><tr><th>Layer</th><th>Lives in</th><th>Runtime</th><th>Talks to a model?</th></tr></thead><tbody><tr><td>Deterministic CLI</td><td><code>src/*.js</code></td><td>Plain Node ESM</td><td>No</td></tr><tr><td>Model-facing</td><td><code>plugin/</code> (commands, skills, agents)</td><td>Claude Code</td><td>Yes</td></tr></tbody></table><p>The <strong>CLI layer</strong> is ordinary Node with a single runtime dependency. It does the deterministic work: detecting the project, resolving roles to providers, ranking candidates, scoring artifacts against a gate, computing prioritization math, validating pipelines. Anything that can be answered by code is answered by code.</p><p>The <strong>model-facing layer</strong> is markdown that Claude Code loads as a plugin. It instructs the model how to drive a run, calling the CLI for every deterministic decision and using Claude Code&#39;s subagent dispatch for the judgment work.</p><blockquote><p>Routing, scoring, and validation are reproducible because code owns them. Drafting, reviewing, and classifying are the model&#39;s job.</p></blockquote><h2 id="roles-and-the-resolution-ladder" tabindex="-1">Roles and the resolution ladder <a class="header-anchor" href="#roles-and-the-resolution-ladder" aria-label="Permalink to &quot;Roles and the resolution ladder&quot;">​</a></h2><p>Muster names a fixed vocabulary of <strong>roles</strong>, the kinds of work a crew might need (<code>implement</code>, <code>code-review</code>, <code>test-author</code>, <code>debug</code>, <code>security-review</code>, <code>author</code>, <code>research</code>, <code>score</code>, <code>humanize</code>, <code>prompt-quality</code>, <code>improve</code>, and more — 23 in all). Roles are the stable interface: pipelines and commands ask for a role, not for a specific tool.</p><p>Each role resolves through a <strong>ladder</strong> of provider sources, best available first:</p><ol><li>An installed external provider (a plugin, agent, or MCP server you already have)</li><li>A Muster built-in agent</li><li>A Muster built-in skill</li><li>Inline (the model does it directly, no specialist attached)</li></ol><p>Because the ladder always terminates at inline, <strong>every role resolves to something</strong>. Muster works on bare Claude Code and gets better as you install more tools.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> capabilities</span></span></code></pre></div><p>For each role this reports <code>chosen</code> (the winner), <code>chain</code> (the full fallback list, always ending in <code>inline</code>), <code>recommendations</code> (installable providers that would beat the current fallback), and <code>model</code>.</p><h2 id="description-search" tabindex="-1">Description-search <a class="header-anchor" href="#description-search" aria-label="Permalink to &quot;Description-search&quot;">​</a></h2><p>The role enum is fixed, but the set of providers is not, and some specialists do not map cleanly onto a named role. The escape hatch is <strong>description-search</strong>: a deterministic token-overlap ranker, no LLM call.</p><div class="language-sh vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">sh</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @adnova-group/muster</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> match</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;audit this code for security vulnerabilities&quot;</span></span></code></pre></div><p>It tokenizes the task, scores every catalog provider by overlap (id, roles, and keywords weighted high; the free-text description weighted low), and boosts installed providers so a present tool edges out an equal-scoring fallback. That is how a task surfaces the right specialist even when it never names a role.</p><h2 id="per-role-model-selection" tabindex="-1">Per-role model selection <a class="header-anchor" href="#per-role-model-selection" aria-label="Permalink to &quot;Per-role model selection&quot;">​</a></h2><p>Each resolved role carries a model picked to fit the work, so quota spend tracks difficulty.</p><table tabindex="0"><thead><tr><th>Tier</th><th>Roles</th><th>Why</th></tr></thead><tbody><tr><td>haiku</td><td><code>code-navigation</code>, <code>docs-research</code>, <code>research</code></td><td>Mechanical: locating, gathering, scanning</td></tr><tr><td>sonnet</td><td>everything else (the default)</td><td>Implementation, review, authoring, scoring</td></tr><tr><td>fable</td><td>the tournament <code>judge</code>, <code>architecture-review</code>, <code>improve</code>, <code>advisor</code></td><td>Heavy judgment</td></tr><tr><td>opus</td><td>fallback only (fable -&gt; opus via <code>fallbackModelFor</code>)</td><td>Used when fable is unavailable on the plan</td></tr></tbody></table><p>The orchestrator passes the chosen model as the dispatch override when it spawns each subagent.</p><h2 id="provider-kinds" tabindex="-1">Provider kinds <a class="header-anchor" href="#provider-kinds" aria-label="Permalink to &quot;Provider kinds&quot;">​</a></h2><p>A provider resolves to one of four kinds, which decides how it is dispatched:</p><ul><li><strong>agent</strong>: a subagent definition, dispatched by <code>subagent_type</code>.</li><li><strong>skill</strong>: a markdown skill injected into a generic subagent.</li><li><strong>mcp</strong>: an installed MCP server, surfaced as a tool.</li><li><strong>inline</strong>: no specialist; the model does the work directly.</li></ul><p>When a role resolves to an agent whose type is not yet dispatchable in the running session (for example, plugin agents installed before a restart), the orchestrator falls back to a generic subagent with the resolved provider&#39;s brief injected. The model override still applies, so model selection is never lost on the fallback.</p><p>Next: <a href="/muster/reference/modes">The four modes</a>.</p>',30)])])}const g=t(i,[["render",r]]);export{u as __pageData,g as default};
